#!/usr/bin/env python3
"""Restore a directory produced by compress.py back to its original layout."""

from __future__ import annotations

import argparse
import hashlib
import json
import os
import shutil
import stat
import sys
import tempfile
from pathlib import Path
from typing import Any, Iterator


MAX_FILE_BYTES = 15_000_000
MAX_DIR_ENTRIES = 30
CHUNK_BYTES = 1024 * 1024
INDEX_NAME = ".reshard_index.json"
VERSION = 1


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(description="Restore a directory produced by compress.py in place.")
    parser.add_argument("resharded_dir", type=Path)
    return parser.parse_args()


def base30_digits(index: int, width: int) -> list[int]:
    digits = [0] * width
    value = index
    for pos in range(width - 1, -1, -1):
        digits[pos] = value % MAX_DIR_ENTRIES
        value //= MAX_DIR_ENTRIES
    if value:
        raise ValueError("index does not fit requested bounded path width")
    return digits


def path_width(count: int) -> int:
    width = 1
    capacity = MAX_DIR_ENTRIES
    while count > capacity:
        width += 1
        capacity *= MAX_DIR_ENTRIES
    return width


def bounded_path(base: Path, index: int, count: int, suffix: str) -> Path:
    width = path_width(count)
    digits = base30_digits(index, width)
    path = base
    for digit in digits[:-1]:
        path /= f"{digit:02d}"
    return path / f"{digits[-1]:02d}{suffix}"


def load_index(root: Path) -> dict[str, Any]:
    index_path = root / INDEX_NAME
    if not index_path.is_file():
        raise FileNotFoundError(f"missing reshard index: {index_path}")
    with index_path.open("r", encoding="utf-8") as handle:
        index = json.load(handle)
    if index.get("format") != "dataset-resharder" or index.get("version") != VERSION:
        raise ValueError("unsupported or invalid reshard index")
    if index.get("max_file_bytes") != MAX_FILE_BYTES or index.get("max_dir_entries") != MAX_DIR_ENTRIES:
        raise ValueError("reshard limits in index do not match this decompressor")
    return index


def safe_join(root: Path, relative: str) -> Path:
    rel = Path(relative)
    if rel.is_absolute() or any(part in ("", ".", "..") for part in rel.parts):
        raise ValueError(f"unsafe path in metadata: {relative!r}")
    target = root / rel
    target_parent = target.parent.resolve()
    root_resolved = root.resolve()
    try:
        target_parent.relative_to(root_resolved)
    except ValueError as exc:
        raise ValueError(f"path escapes restore directory: {relative!r}") from exc
    return target


def iter_metadata(root: Path, index: dict[str, Any]) -> Iterator[dict[str, Any]]:
    count = int(index["metadata_shards"])
    base = root / index["metadata_dir"]
    for shard_index in range(count):
        path = bounded_path(base, shard_index, count, ".jsonl")
        with path.open("r", encoding="utf-8") as handle:
            for line in handle:
                if line.strip():
                    yield json.loads(line)


def expected_artifacts(root: Path, index: dict[str, Any]) -> set[Path]:
    expected = {root / INDEX_NAME}
    if int(index["data_shards"]):
        expected.add(root / index["data_dir"])
    if int(index["metadata_shards"]):
        expected.add(root / index["metadata_dir"])
    return expected


def ensure_no_unexpected_entries(root: Path, index: dict[str, Any]) -> None:
    expected = expected_artifacts(root, index)
    unexpected = [path.name for path in root.iterdir() if path not in expected]
    if unexpected:
        names = ", ".join(sorted(unexpected))
        raise ValueError(f"resharded directory contains unexpected entries: {names}")


def copy_piece(source: Path, offset: int, length: int, output, digest: hashlib._Hash) -> None:
    remaining = length
    with source.open("rb") as handle:
        handle.seek(offset)
        while remaining:
            chunk = handle.read(min(CHUNK_BYTES, remaining))
            if not chunk:
                raise OSError(f"unexpected end of shard: {source}")
            output.write(chunk)
            digest.update(chunk)
            remaining -= len(chunk)


def restore_file(root: Path, data_root: Path, data_count: int, record: dict[str, Any]) -> None:
    target = safe_join(root, record["path"])
    target.parent.mkdir(parents=True, exist_ok=True)
    digest = hashlib.sha256()
    written = 0
    with target.open("wb") as output:
        for shard_index, offset, length in record["pieces"]:
            source = bounded_path(data_root, int(shard_index), data_count, ".bin")
            copy_piece(source, int(offset), int(length), output, digest)
            written += int(length)
    if written != int(record["size"]):
        raise ValueError(f"restored size mismatch for {record['path']}")
    if digest.hexdigest() != record["sha256"]:
        raise ValueError(f"restored checksum mismatch for {record['path']}")
    os.chmod(target, int(record["mode"]))
    os.utime(target, ns=(int(record["mtime_ns"]), int(record["mtime_ns"])))


def restore_symlink(root: Path, record: dict[str, Any]) -> None:
    target = safe_join(root, record["path"])
    target.parent.mkdir(parents=True, exist_ok=True)
    os.symlink(record["target"], target)
    try:
        os.utime(target, ns=(int(record["mtime_ns"]), int(record["mtime_ns"])), follow_symlinks=False)
    except (NotImplementedError, OSError):
        pass


def restore_records(resharded_root: Path, restore_root: Path, index: dict[str, Any]) -> tuple[int, int]:
    data_count = int(index["data_shards"])
    data_root = resharded_root / index["data_dir"]
    directories: list[dict[str, Any]] = []
    file_count = 0
    dir_count = 0

    for record in iter_metadata(resharded_root, index):
        record_type = record.get("type")
        if record_type == "dir":
            target = safe_join(restore_root, record["path"])
            target.mkdir(parents=True, exist_ok=True)
            os.chmod(target, int(record["mode"]))
            directories.append(record)
            dir_count += 1
        elif record_type == "file":
            restore_file(restore_root, data_root, data_count, record)
            file_count += 1
        elif record_type == "symlink":
            restore_symlink(restore_root, record)
            file_count += 1
        else:
            raise ValueError(f"unknown metadata record type: {record_type!r}")

    for record in sorted(directories, key=lambda item: item["path"].count("/"), reverse=True):
        target = safe_join(restore_root, record["path"])
        os.utime(target, ns=(int(record["mtime_ns"]), int(record["mtime_ns"])))

    return file_count, dir_count


def remove_artifacts(root: Path, index: dict[str, Any]) -> None:
    for artifact in sorted(expected_artifacts(root, index), key=lambda path: len(path.parts), reverse=True):
        if artifact.is_dir():
            shutil.rmtree(artifact)
        elif artifact.exists() or artifact.is_symlink():
            artifact.unlink()


def move_children(source: Path, dest: Path) -> None:
    for child in source.iterdir():
        shutil.move(str(child), dest / child.name)


def main() -> int:
    args = parse_args()
    root = args.resharded_dir.resolve()
    if not root.is_dir():
        print(f"error: resharded directory does not exist: {root}", file=sys.stderr)
        return 2

    temp_root: Path | None = None
    try:
        index = load_index(root)
        ensure_no_unexpected_entries(root, index)
        temp_root = Path(tempfile.mkdtemp(prefix=f".{root.name}.restore-", dir=root.parent))
        file_count, dir_count = restore_records(root, temp_root, index)
        ensure_no_unexpected_entries(root, index)
        remove_artifacts(root, index)
        move_children(temp_root, root)
        temp_root.rmdir()
    except Exception as exc:
        if temp_root is not None and temp_root.exists():
            shutil.rmtree(temp_root)
        print(f"error: {exc}", file=sys.stderr)
        return 1

    print(f"restored {file_count} files and {dir_count} directories")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
